```python
import os
import subprocess
import time
import random

def create_directory():
    if not os.path.exists('cryptocurrency'):
        os.makedirs('cryptocurrency')

def run_command():
    subprocess.run(['sudo','service', 'cryptocurrency','start'])

def stop_command():
    subprocess.run(['sudo','service', 'cryptocurrency','stop'])

def remove_directory():
    if os.path.exists('cryptocurrency'):
        os.rmdir('cryptocurrency')

def main():
    create_directory()
    run_command()
    time.sleep(60)
    stop_command()
    remove_directory()

if __name__ == '__main__':
    main()
